module Metadata =
  struct
    type nonrec t = (MetadataKey.t * MetadataValue.t) list
    let make i = i
    let of_header xs =
      make
        (List.filter_map xs
           ~f:(fun (k, v) ->
                 (Base.String.chop_prefix k ~prefix:"x-amz-meta-") |>
                   (Option.map
                      ~f:(fun chopped ->
                            ((MetadataKey.of_string chopped),
                              (MetadataValue.of_string v))))))
    let to_value xs =
      (xs |>
         (List.map
            ~f:(fun (x, y) ->
                  (MetadataKey.to_value x) |>
                    (fun x -> (MetadataValue.to_value y) |> (fun y -> (x, y))))))
        |> (fun x -> `Map x)
    let to_query v = to_query to_value v
    let of_xml _ =
      failwith "of_xml_converter_of_shape: Map_shape case not implemented"
    let of_json j =
      object_of_json ~key_of_string:MetadataKey.of_string
        ~of_json:MetadataValue.of_json j
    let to_json v = composed_to_json to_value v
  end
