       "Request to filter the contents of an Amazon S3 object based on a simple Structured Query Language (SQL) statement. In the request, along with the SQL expression, you must specify a data serialization format (JSON or CSV) of the object. Amazon S3 uses this to parse object data into records. It returns only records that match the specified SQL expression. You must also specify the data serialization format for the response. For more information, see S3Select API Documentation."]
module SelectObjectContentOutput =
  struct
    type nonrec t =
      {
      payload: SelectObjectContentEventStream.t option
        [@ocaml.doc "The array of results."]}
    type nonrec error =
      [ `Unknown_operation_error of (string * string option) ]
    let make ?payload = fun () -> { payload }
    let error_of_json name json =
      match name with
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Payload",
           (Option.map x.payload ~f:SelectObjectContentEventStream.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let payload =
        (Option.map ~f:SelectObjectContentEventStream.of_xml)
          (Xml.child xml_arg0 "Payload") in
      make ?payload ()
    let of_json json =
      let payload =
        field_map json "Payload" SelectObjectContentEventStream.of_json in
      make ?payload ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "This action filters the contents of an Amazon S3 object based on a simple structured query language (SQL) statement. In the request, along with the SQL expression, you must also specify a data serialization format (JSON, CSV, or Apache Parquet) of the object. Amazon S3 uses this format to parse object data into records, and returns only records that match the specified SQL expression. You must also specify the data serialization format for the response. This action is not supported by Amazon S3 on Outposts. For more information about Amazon S3 Select, see Selecting Content from Objects and SELECT Command in the Amazon S3 User Guide. For more information about using SQL with Amazon S3 Select, see SQL Reference for Amazon S3 Select and S3 Glacier Select in the Amazon S3 User Guide. Permissions You must have s3:GetObject permission for this operation.\194\160Amazon S3 Select does not support anonymous access. For more information about permissions, see Specifying Permissions in a Policy in the Amazon S3 User Guide. Object Data Formats You can use Amazon S3 Select to query objects that have the following format properties: CSV, JSON, and Parquet - Objects must be in CSV, JSON, or Parquet format. UTF-8 - UTF-8 is the only encoding type Amazon S3 Select supports. GZIP or BZIP2 - CSV and JSON files can be compressed using GZIP or BZIP2. GZIP and BZIP2 are the only compression formats that Amazon S3 Select supports for CSV and JSON files. Amazon S3 Select supports columnar compression for Parquet using GZIP or Snappy. Amazon S3 Select does not support whole-object compression for Parquet objects. Server-side encryption - Amazon S3 Select supports querying objects that are protected with server-side encryption. For objects that are encrypted with customer-provided encryption keys (SSE-C), you must use HTTPS, and you must use the headers that are documented in the GetObject. For more information about SSE-C, see Server-Side Encryption (Using Customer-Provided Encryption Keys) in the Amazon S3 User Guide. For objects that are encrypted with Amazon S3 managed encryption keys (SSE-S3) and Amazon Web Services KMS keys (SSE-KMS), server-side encryption is handled transparently, so you don't need to specify anything. For more information about server-side encryption, including SSE-S3 and SSE-KMS, see Protecting Data Using Server-Side Encryption in the Amazon S3 User Guide. Working with the Response Body Given the response size is unknown, Amazon S3 Select streams the response as a series of messages and includes a Transfer-Encoding header with chunked as its value in the response. For more information, see Appendix: SelectObjectContent Response. GetObject Support The SelectObjectContent action does not support the following GetObject functionality. For more information, see GetObject. Range: Although you can specify a scan range for an Amazon S3 Select request (see SelectObjectContentRequest - ScanRange in the request parameters), you cannot specify the range of bytes of an object to return. GLACIER, DEEP_ARCHIVE and REDUCED_REDUNDANCY storage classes: You cannot specify the GLACIER, DEEP_ARCHIVE, or REDUCED_REDUNDANCY storage classes. For more information, about storage classes see Storage Classes in the Amazon S3 User Guide. Special Errors For a list of special errors for this operation, see List of SELECT Object Content Error Codes Related Resources GetObject GetBucketLifecycleConfiguration PutBucketLifecycleConfiguration"]
module RestoreObjectRequest =
  struct
    type nonrec t =
      {
      bucket: BucketName.t
        [@ocaml.doc
          "The bucket name containing the object to restore. When using this action with an access point, you must direct requests to the access point hostname. The access point hostname takes the form AccessPointName-AccountId.s3-accesspoint.Region.amazonaws.com. When using this action with an access point through the Amazon Web Services SDKs, you provide the access point ARN in place of the bucket name. For more information about access point ARNs, see Using access points in the Amazon S3 User Guide. When using this action with Amazon S3 on Outposts, you must direct requests to the S3 on Outposts hostname. The S3 on Outposts hostname takes the form AccessPointName-AccountId.outpostID.s3-outposts.Region.amazonaws.com. When using this action with S3 on Outposts through the Amazon Web Services SDKs, you provide the Outposts bucket ARN in place of the bucket name. For more information about S3 on Outposts ARNs, see Using Amazon S3 on Outposts in the Amazon S3 User Guide."];
      key: ObjectKey.t
        [@ocaml.doc "Object key for which the action was initiated."];
      versionId: ObjectVersionId.t option
        [@ocaml.doc
          "VersionId used to reference a specific version of the object."];
      restoreRequest: RestoreRequest.t option ;
      requestPayer: RequestPayer.t option ;
      checksumAlgorithm: ChecksumAlgorithm.t option
        [@ocaml.doc
          "Indicates the algorithm used to create the checksum for the object when using the SDK. This header will not provide any additional functionality if not using the SDK. When sending this header, there must be a corresponding x-amz-checksum or x-amz-trailer header sent. Otherwise, Amazon S3 fails the request with the HTTP status code 400 Bad Request. For more information, see Checking object integrity in the Amazon S3 User Guide. If you provide an individual checksum, Amazon S3 ignores any provided ChecksumAlgorithm parameter."];
      expectedBucketOwner: AccountId.t option
        [@ocaml.doc
          "The account ID of the expected bucket owner. If the bucket is owned by a different account, the request fails with the HTTP status code 403 Forbidden (access denied)."]}
    let context_ = "RestoreObjectRequest"
    let make ?versionId =
      fun ?restoreRequest ->
        fun ?requestPayer ->
          fun ?checksumAlgorithm ->
            fun ?expectedBucketOwner ->
              fun ~bucket ->
                fun ~key ->
                  fun () ->
                    {
                      versionId;
                      restoreRequest;
                      requestPayer;
                      checksumAlgorithm;
                      expectedBucketOwner;
                      bucket;
                      key
                    }
    let to_value x =
      structure_to_value
        [("Bucket", (Some (BucketName.to_value x.bucket)));
        ("Key", (Some (ObjectKey.to_value x.key)));
        ("versionId", (Option.map x.versionId ~f:ObjectVersionId.to_value));
        ("RestoreRequest",
          (Option.map x.restoreRequest ~f:RestoreRequest.to_value));
        ("x-amz-request-payer",
          (Option.map x.requestPayer ~f:RequestPayer.to_value));
        ("x-amz-sdk-checksum-algorithm",
          (Option.map x.checksumAlgorithm ~f:ChecksumAlgorithm.to_value));
        ("x-amz-expected-bucket-owner",
          (Option.map x.expectedBucketOwner ~f:AccountId.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let expectedBucketOwner =
        (Option.map ~f:AccountId.of_xml)
          (Xml.child xml_arg0 "x-amz-expected-bucket-owner") in
      let checksumAlgorithm =
        (Option.map ~f:ChecksumAlgorithm.of_xml)
          (Xml.child xml_arg0 "x-amz-sdk-checksum-algorithm") in
      let requestPayer =
        (Option.map ~f:RequestPayer.of_xml)
          (Xml.child xml_arg0 "x-amz-request-payer") in
      let restoreRequest =
        (Option.map ~f:RestoreRequest.of_xml)
          (Xml.child xml_arg0 "RestoreRequest") in
      let versionId =
        (Option.map ~f:ObjectVersionId.of_xml)
          (Xml.child xml_arg0 "versionId") in
      let key =
        ObjectKey.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Key") in
      let bucket =
        BucketName.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Bucket") in
      make ?expectedBucketOwner ?checksumAlgorithm ?requestPayer
        ?restoreRequest ?versionId ~key ~bucket ()
    let of_json json =
      let expectedBucketOwner =
        field_map json "ExpectedBucketOwner" AccountId.of_json in
      let checksumAlgorithm =
        field_map json "ChecksumAlgorithm" ChecksumAlgorithm.of_json in
      let requestPayer = field_map json "RequestPayer" RequestPayer.of_json in
      let restoreRequest =
        field_map json "RestoreRequest" RestoreRequest.of_json in
      let versionId = field_map json "VersionId" ObjectVersionId.of_json in
      let key = field_map_exn json "Key" ObjectKey.of_json in
      let bucket = field_map_exn json "Bucket" BucketName.of_json in
      make ?expectedBucketOwner ?checksumAlgorithm ?requestPayer
        ?restoreRequest ?versionId ~key ~bucket ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Restores an archived copy of an object back into Amazon S3 This action is not supported by Amazon S3 on Outposts. This action performs the following types of requests: select - Perform a select query on an archived object restore an archive - Restore an archived object To use this operation, you must have permissions to perform the s3:RestoreObject action. The bucket owner has this permission by default and can grant this permission to others. For more information about permissions, see Permissions Related to Bucket Subresource Operations and Managing Access Permissions to Your Amazon S3 Resources in the Amazon S3 User Guide. Querying Archives with Select Requests You use a select type of request to perform SQL queries on archived objects. The archived objects that are being queried by the select request must be formatted as uncompressed comma-separated values (CSV) files. You can run queries and custom analytics on your archived data without having to restore your data to a hotter Amazon S3 tier. For an overview about select requests, see Querying Archived Objects in the Amazon S3 User Guide. When making a select request, do the following: Define an output location for the select query's output. This must be an Amazon S3 bucket in the same Amazon Web Services Region as the bucket that contains the archive object that is being queried. The Amazon Web Services account that initiates the job must have permissions to write to the S3 bucket. You can specify the storage class and encryption for the output objects stored in the bucket. For more information about output, see Querying Archived Objects in the Amazon S3 User Guide. For more information about the S3 structure in the request body, see the following: PutObject Managing Access with ACLs in the Amazon S3 User Guide Protecting Data Using Server-Side Encryption in the Amazon S3 User Guide Define the SQL expression for the SELECT type of restoration for your query in the request body's SelectParameters structure. You can use expressions like the following examples. The following expression returns all records from the specified object. SELECT * FROM Object Assuming that you are not using any headers for data stored in the object, you can specify columns with positional headers. SELECT s._1, s._2 FROM Object s WHERE s._3 > 100 If you have headers and you set the fileHeaderInfo in the CSV structure in the request body to USE, you can specify headers in the query. (If you set the fileHeaderInfo field to IGNORE, the first row is skipped for the query.) You cannot mix ordinal positions with header column names. SELECT s.Id, s.FirstName, s.SSN FROM S3Object s For more information about using SQL with S3 Glacier Select restore, see SQL Reference for Amazon S3 Select and S3 Glacier Select in the Amazon S3 User Guide. When making a select request, you can also do the following: To expedite your queries, specify the Expedited tier. For more information about tiers, see \"Restoring Archives,\" later in this topic. Specify details about the data serialization format of both the input object that is being queried and the serialization of the CSV-encoded query results. The following are additional important facts about the select feature: The output results are new Amazon S3 objects. Unlike archive retrievals, they are stored until explicitly deleted-manually or through a lifecycle policy. You can issue more than one select request on the same Amazon S3 object. Amazon S3 doesn't deduplicate requests, so avoid issuing duplicate requests. Amazon S3 accepts a select request even if the object has already been restored. A select request doesn\226\128\153t return error response 409. Restoring objects Objects that you archive to the S3 Glacier or S3 Glacier Deep Archive storage class, and S3 Intelligent-Tiering Archive or S3 Intelligent-Tiering Deep Archive tiers are not accessible in real time. For objects in Archive Access or Deep Archive Access tiers you must first initiate a restore request, and then wait until the object is moved into the Frequent Access tier. For objects in S3 Glacier or S3 Glacier Deep Archive storage classes you must first initiate a restore request, and then wait until a temporary copy of the object is available. To access an archived object, you must restore the object for the duration (number of days) that you specify. To restore a specific object version, you can provide a version ID. If you don't provide a version ID, Amazon S3 restores the current version. When restoring an archived object (or using a select request), you can specify one of the following data access tier options in the Tier element of the request body: Expedited - Expedited retrievals allow you to quickly access your data stored in the S3 Glacier storage class or S3 Intelligent-Tiering Archive tier when occasional urgent requests for a subset of archives are required. For all but the largest archived objects (250 MB+), data accessed using Expedited retrievals is typically made available within 1\226\128\1475 minutes. Provisioned capacity ensures that retrieval capacity for Expedited retrievals is available when you need it. Expedited retrievals and provisioned capacity are not available for objects stored in the S3 Glacier Deep Archive storage class or S3 Intelligent-Tiering Deep Archive tier. Standard - Standard retrievals allow you to access any of your archived objects within several hours. This is the default option for retrieval requests that do not specify the retrieval option. Standard retrievals typically finish within 3\226\128\1475 hours for objects stored in the S3 Glacier storage class or S3 Intelligent-Tiering Archive tier. They typically finish within 12 hours for objects stored in the S3 Glacier Deep Archive storage class or S3 Intelligent-Tiering Deep Archive tier. Standard retrievals are free for objects stored in S3 Intelligent-Tiering. Bulk - Bulk retrievals are the lowest-cost retrieval option in S3 Glacier, enabling you to retrieve large amounts, even petabytes, of data inexpensively. Bulk retrievals typically finish within 5\226\128\14712 hours for objects stored in the S3 Glacier storage class or S3 Intelligent-Tiering Archive tier. They typically finish within 48 hours for objects stored in the S3 Glacier Deep Archive storage class or S3 Intelligent-Tiering Deep Archive tier. Bulk retrievals are free for objects stored in S3 Intelligent-Tiering. For more information about archive retrieval options and provisioned capacity for Expedited data access, see Restoring Archived Objects in the Amazon S3 User Guide. You can use Amazon S3 restore speed upgrade to change the restore speed to a faster speed while it is in progress. For more information, see Upgrading the speed of an in-progress restore in the Amazon S3 User Guide. To get the status of object restoration, you can send a HEAD request. Operations return the x-amz-restore header, which provides information about the restoration status, in the response. You can use Amazon S3 event notifications to notify you when a restore is initiated or completed. For more information, see Configuring Amazon S3 Event Notifications in the Amazon S3 User Guide. After restoring an archived object, you can update the restoration period by reissuing the request with a new period. Amazon S3 updates the restoration period relative to the current time and charges only for the request-there are no data transfer charges. You cannot update the restoration period when Amazon S3 is actively processing your current restore request for the object. If your bucket has a lifecycle configuration with a rule that includes an expiration action, the object expiration overrides the life span that you specify in a restore request. For example, if you restore an object copy for 10 days, but the object is scheduled to expire in 3 days, Amazon S3 deletes the object in 3 days. For more information about lifecycle configuration, see PutBucketLifecycleConfiguration and Object Lifecycle Management in Amazon S3 User Guide. Responses A successful action returns either the 200 OK or 202 Accepted status code. If the object is not previously restored, then Amazon S3 returns 202 Accepted in the response. If the object is previously restored, Amazon S3 returns 200 OK in the response. Special Errors Code: RestoreAlreadyInProgress Cause: Object restore is already in progress. (This error does not apply to SELECT type requests.) HTTP Status Code: 409 Conflict SOAP Fault Code Prefix: Client Code: GlacierExpeditedRetrievalNotAvailable Cause: expedited retrievals are currently not available. Try again later. (Returned if there is insufficient capacity to process the Expedited request. This error applies only to Expedited retrievals and not to S3 Standard or Bulk retrievals.) HTTP Status Code: 503 SOAP Fault Code Prefix: N/A Related Resources PutBucketLifecycleConfiguration GetBucketNotificationConfiguration SQL Reference for Amazon S3 Select and S3 Glacier Select in the Amazon S3 User Guide"]
module RestoreObjectOutput =
  struct
    type nonrec t =
      {
      requestCharged: RequestCharged.t option ;
      restoreOutputPath: RestoreOutputPath.t option
        [@ocaml.doc
          "Indicates the path in the provided S3 output location where Select results will be restored to."]}
    type nonrec error =
      [ `ObjectAlreadyInActiveTierError of ObjectAlreadyInActiveTierError.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?requestCharged =
      fun ?restoreOutputPath ->
        fun () -> { requestCharged; restoreOutputPath }
    let error_of_json name json =
      match name with
      | "ObjectAlreadyInActiveTierError" ->
          `ObjectAlreadyInActiveTierError
            (ObjectAlreadyInActiveTierError.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ObjectAlreadyInActiveTierError" ->
          `ObjectAlreadyInActiveTierError
            (ObjectAlreadyInActiveTierError.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ObjectAlreadyInActiveTierError e ->
          `Assoc
            [("error", (`String "ObjectAlreadyInActiveTierError"));
            ("details", (ObjectAlreadyInActiveTierError.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let of_header_and_body =
      ((fun (xs, pipe) ->
          make
            ?requestCharged:(Option.map
                               ((List.Assoc.find ~equal:String.Caseless.equal)
                                  xs "x-amz-request-charged")
                               ~f:RequestCharged.of_string)
            ?restoreOutputPath:(Option.map
                                  ((List.Assoc.find
                                      ~equal:String.Caseless.equal) xs
                                     "x-amz-restore-output-path")
                                  ~f:RestoreOutputPath.of_string) ())
      [@warning "-27"])
    let to_value x =
      structure_to_value
        [("x-amz-request-charged",
           (Option.map x.requestCharged ~f:RequestCharged.to_value));
        ("x-amz-restore-output-path",
          (Option.map x.restoreOutputPath ~f:RestoreOutputPath.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let restoreOutputPath =
        (Option.map ~f:RestoreOutputPath.of_xml)
          (Xml.child xml_arg0 "x-amz-restore-output-path") in
      let requestCharged =
        (Option.map ~f:RequestCharged.of_xml)
          (Xml.child xml_arg0 "x-amz-request-charged") in
      make ?restoreOutputPath ?requestCharged ()
    let of_json json =
      let restoreOutputPath =
        field_map json "RestoreOutputPath" RestoreOutputPath.of_json in
      let requestCharged =
        field_map json "RequestCharged" RequestCharged.of_json in
      make ?restoreOutputPath ?requestCharged ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
